import json
from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import List, Dict, Any, Optional, Protocol


# ==================== Data Models ====================
@dataclass
class Item:
    """Data model for input items with validation."""
    id: str
    value: float
    type: Optional[str] = None

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> 'Item':
        """Factory method to create Item from dictionary with type conversion."""
        return cls(
            id=str(data.get('id', '')),
            value=float(data.get('value', 0)),
            type=data.get('type')
        )


@dataclass
class Result:
    """Data model for processed results."""
    id: str
    value: float
    status: str


# ==================== Processing Strategies ====================
class ProcessingStrategy(Protocol):
    """Protocol defining the processing strategy interface."""
    def process(self, item: Item) -> Optional[Result]:
        """Process an item and return a Result or None if skipped."""
        ...


class FastProcessingStrategy:
    """Strategy for fast processing mode."""

    def __init__(self, flag1: bool = False, flag2: bool = True):
        self.flag1 = flag1
        self.flag2 = flag2

    def process(self, item: Item) -> Optional[Result]:
        """Process item according to fast mode rules."""
        if item.type == 'A':
            return self._process_type_a(item)
        elif item.type == 'B':
            return self._process_type_b(item)
        else:
            return self._process_other_type(item)

    def _process_type_a(self, item: Item) -> Result:
        """Process items of type A."""
        value = item.value * 1.1 if self.flag1 else item.value

        if value > 100:
            if self.flag2:
                return Result(item.id, value, 'high')
            else:
                return Result(item.id, value * 0.9, 'adjusted')
        else:
            return Result(item.id, value, 'normal')

    def _process_type_b(self, item: Item) -> Result:
        """Process items of type B."""
        value = item.value * 0.95
        return Result(item.id, value, 'discounted')

    def _process_other_type(self, item: Item) -> Optional[Result]:
        """Process items of other types."""
        if self.flag1 and self.flag2:
            return Result(item.id, 0, 'skip')
        return None


class CarefulProcessingStrategy:
    """Strategy for careful processing mode."""

    def process(self, item: Item) -> Result:
        """Process item with validation and error handling."""
        try:
            value = item.value
            if value < 0:
                raise ValueError("Negative value not allowed")
            return Result(item.id, value, 'validated')
        except (ValueError, TypeError):
            return Result(item.id, 0, 'error')


# ==================== Output Formatters ====================
class OutputFormatter(Protocol):
    """Protocol defining the output formatting interface."""
    def format(self, results: List[Result]) -> Any:
        """Format results into desired output type."""
        ...


class JsonFormatter:
    """Formatter for JSON output."""

    def format(self, results: List[Result]) -> str:
        """Convert results to JSON string."""
        return json.dumps([
            {'id': r.id, 'val': r.value, 'status': r.status}
            for r in results
        ])


class CsvFormatter:
    """Formatter for CSV output."""

    def format(self, results: List[Result]) -> str:
        """Convert results to CSV string."""
        return '\n'.join(
            f"{r.id},{r.value},{r.status}"
            for r in results
        )


class RawFormatter:
    """Formatter for raw Python objects."""

    def format(self, results: List[Result]) -> List[Dict[str, Any]]:
        """Convert results to list of dictionaries."""
        return [
            {'id': r.id, 'val': r.value, 'status': r.status}
            for r in results
        ]


# ==================== Main Processor ====================
class DataProcessor:
    """Main processor class coordinating strategy and formatting."""

    def __init__(
        self,
        strategy: ProcessingStrategy,
        formatter: OutputFormatter
    ):
        self.strategy = strategy
        self.formatter = formatter

    def process(self, data: List[Dict[str, Any]]) -> Any:
        """Process list of data items using the configured strategy."""
        results = []

        for item_data in data:
            try:
                item = Item.from_dict(item_data)
                result = self.strategy.process(item)
                if result:  # Skip None results
                    results.append(result)
            except Exception as e:
                # Log error and continue processing other items
                print(f"Error processing item {item_data.get('id')}: {e}")
                results.append(Result(
                    id=str(item_data.get('id', 'unknown')),
                    value=0,
                    status='error'
                ))

        return self.formatter.format(results)


# ==================== Factory Functions ====================
def create_strategy(
    mode: str,
    flag1: bool = False,
    flag2: bool = True
) -> ProcessingStrategy:
    """Factory function to create processing strategy."""
    strategies = {
        'fast': FastProcessingStrategy(flag1, flag2),
        'careful': CarefulProcessingStrategy(),
    }

    if mode not in strategies:
        raise ValueError(f"Unknown processing mode: {mode}")

    return strategies[mode]


def create_formatter(output_type: str) -> OutputFormatter:
    """Factory function to create output formatter."""
    formatters = {
        'json': JsonFormatter(),
        'csv': CsvFormatter(),
        'raw': RawFormatter(),
    }

    if output_type not in formatters:
        raise ValueError(f"Unknown output type: {output_type}")

    return formatters[output_type]


# ==================== Public API ====================
def process(
    data: List[Dict[str, Any]],
    mode: str,
    flag1: bool = False,
    flag2: bool = True,
    output_type: str = 'json'
) -> Any:
    """
    Public API function matching the original interface.

    Args:
        data: List of dictionaries containing item data
        mode: Processing mode ('fast' or 'careful')
        flag1: First flag for fast mode
        flag2: Second flag for fast mode
        output_type: Output format ('json', 'csv', or 'raw')

    Returns:
        Formatted results according to output_type
    """
    strategy = create_strategy(mode, flag1, flag2)
    formatter = create_formatter(output_type)
    processor = DataProcessor(strategy, formatter)

    return processor.process(data)
```

## Design Decisions Explained:

### 1. **Data Models (Item, Result)**
- **Why**: Replace raw dictionaries with typed data classes
- **Benefits**: Type safety, validation, self-documenting code
- **Item.from_dict()**: Centralizes data validation and conversion

### 2. **Strategy Pattern**
- **Why**: Separate different processing algorithms (fast/careful)
- **Benefits**: Easy to add new modes, single responsibility
- **ProcessingStrategy Protocol**: Defines clear interface for all strategies

### 3. **Factory Pattern**
- **Why**: Centralize object creation logic
- **Benefits**: Easy to extend, hides implementation details
- **create_strategy()/create_formatter()**: Simple, testable creation functions

### 4. **Single Responsibility Principle**
- Each class has one clear purpose:
  - `FastProcessingStrategy`: Only handles fast mode logic
  - `CarefulProcessingStrategy`: Only handles careful mode logic
  - `JsonFormatter`: Only converts to JSON
  - `DataProcessor`: Only coordinates strategy and formatter

### 5. **Error Handling**
- **Why**: Original code had bare except clause
- **Benefits**: Specific error handling, continues processing on errors
- **Implementation**: Catch specific exceptions, log errors, return error results

### 6. **Testability**
- **Why**: Original code was difficult to test
- **Benefits**: Each component can be tested in isolation
- **Example**: Test strategies without formatting, test formatters without processing

### 7. **Type Hints**
- **Why**: Improve code clarity and enable static type checking
- **Benefits**: Better IDE support, catch errors early, self-documenting

### 8. **Separation of Concerns**
- **Processing Logic**: Handled by strategies
- **Data Formatting**: Handled by formatters
- **Coordination**: Handled by DataProcessor
- **Object Creation**: Handled by factories

### 9. **Extensibility**
- **New modes**: Add new strategy class
- **New formats**: Add new formatter class
- **New flags**: Extend strategy constructors
- No need to modify existing code (Open/Closed Principle)

### 10. **Maintainability**
- **Small methods**: Each method does one thing
- **Clear naming**: Intention-revealing names
- **Consistent patterns**: Easy to understand architecture
- **No deep nesting**: Flat structure, easy to follow

### 11. **Preserving Original Interface**
- **Why**: Maintain backward compatibility
- **Benefits**: Existing code can use refactored version without changes
- **Implementation**: `process()` function matches original signature

### 12. **Protocols over ABCs**
- **Why**: Use structural subtyping (duck typing)
- **Benefits**: More flexible, doesn't require inheritance
- **Implementation**: `ProcessingStrategy` and `OutputFormatter` protocols

This refactoring transforms the monolithic function into a clean, maintainable, and extensible system that follows SOLID principles and can be easily tested, extended, and understood.
